      "follow_a_red_blood_cell_through_the_en": "Sigue un glóbulo rojo a través de todo el sistema circulatorio.",
      "right_atrium": "Aurícula derecha",
      "deoxygenated_blood_from_the_body_enter": "La sangre desoxigenada del cuerpo entra en la aurícula derecha por las venas cavas superior e inferior.",
      "right_ventricle": "Ventrículo derecho",
      "blood_passes_through_the_tricuspid_val": "La sangre pasa por la válvula tricúspide hacia el ventrículo derecho, que la bombea hacia los pulmones.",
      "pulmonary_arteries_2": "Arterias pulmonares",
      "the_right_ventricle_ejects_blood_throu": "El ventrículo derecho expulsa la sangre por la válvula pulmonar hacia las arterias pulmonares en dirección a ambos pulmones.",
      "lung_capillaries": "Capilares pulmonares",
      "in_the_alveolar_capillaries_co2_is_rel": "En los capilares alveolares, se libera CO2 y se capta O2 a través de la fina membrana alveolar.",
      "pulmonary_veins": "Venas pulmonares",
      "freshly_oxygenated_blood_returns_to_th": "La sangre recién oxigenada regresa al corazón por las cuatro venas pulmonares.",
      "left_atrium": "Aurícula izquierda",
      "the_four_pulmonary_veins_empty_oxygena": "Las cuatro venas pulmonares vacían la sangre oxigenada en la aurícula izquierda, que se llena y luego la impulsa por la válvula mitral.",
      "left_ventricle": "Ventrículo izquierdo",
      "blood_passes_through_the_mitral_valve_": "La sangre pasa por la válvula mitral hacia el musculoso ventrículo izquierdo, la cámara cardíaca más fuerte.",
      "aorta_2": "Aorta",
      "the_left_ventricle_powerfully_ejects_b": "El ventrículo izquierdo expulsa con fuerza la sangre por la válvula aórtica hacia la aorta, la autopista principal del cuerpo.",
      "body_tissues": "Tejidos corporales",
      "arteries_branch_into_arterioles_and_ca": "Las arterias se ramifican en arteriolas y capilares donde se entregan O2 y nutrientes y se recogen CO2/desechos.",
      "venous_return": "Retorno venoso",
      "deoxygenated_blood_returns_through_ven": "La sangre desoxigenada regresa por vénulas y venas, ayudada por bombas musculares y válvulas, de vuelta a la aurícula derecha.",
      "path_of_air": "Recorrido del aire",
      "trace_the_journey_of_a_breath_of_air_f": "Traza el viaje de una bocanada de aire desde la nariz hasta los alvéolos y de vuelta.",
      "nasal_cavity_2": "Cavidad nasal",
      "air_enters_through_the_nostrils_and_is": "El aire entra por las fosas nasales y es calentado, humidificado y filtrado por las mucosas y los cornetes.",
      "pharynx_2": "Faringe",
      "air_passes_through_the_nasopharynx_and": "El aire pasa por la nasofaringe y la orofaringe, un pasaje compartido con el tracto digestivo.",
      "larynx": "Laringe",
      "air_crosses_the_vocal_cords_in_the_voi": "El aire cruza las cuerdas vocales en el órgano de la voz. La epiglotis protege contra la entrada de comida en la vía aérea.",
      "trachea_2": "Tráquea",
      "the_trachea_windpipe_is_reinforced_by_": "La tráquea está reforzada por anillos de cartílago en forma de C. Los cilios mueven el moco hacia arriba para atrapar partículas.",
      "bronchi": "Bronquios",
      "the_trachea_splits_into_left_and_right": "La tráquea se divide en los bronquios principales izquierdo y derecho, cada uno entrando en un pulmón. Se ramifican en bronquiolos más pequeños.",
      "alveoli_2": "Alvéolos",
      "300_million_grape_like_sacs_where_gas_": "300 millones de sacos parecidos a uvas donde ocurre el intercambio gaseoso. El O2 difunde a la sangre; el CO2 difunde hacia fuera. La superficie equivale a una pista de tenis.",
      "exhalation": "Espiración",
      "the_diaphragm_relaxes_and_rises_reduci": "El diafragma se relaja y asciende, reduciendo el volumen pulmonar. El aire rico en CO2 es expulsado por la misma vía en sentido inverso.",
      "path_of_food": "Recorrido del alimento",
      "follow_a_meal_from_mouth_through_the_e": "Sigue una comida desde la boca a través de todo el sistema digestivo.",
      "mouth": "Boca",
      "teeth_mechanically_break_food_down_sal": "Los dientes trituran mecánicamente el alimento. La amilasa salival inicia la digestión del almidón. La lengua forma el alimento en un bolo.",
      "pharynx_esophagus": "Faringe y esófago",
      "swallowing_pushes_the_bolus_past_the_e": "La deglución empuja el bolo más allá de la epiglotis. Las ondas peristálticas lo desplazan por el esófago de 25 cm en unos 8 segundos.",
      "stomach_2": "Estómago",
      "gastric_acid_ph_1_5_3_5_and_pepsin_bre": "El ácido gástrico (pH 1,5-3,5) y la pepsina descomponen las proteínas. El batido produce quimo durante 2-4 horas.",
      "duodenum": "Duodeno",
      "the_first_25cm_of_the_small_intestine_": "Los primeros 25 cm del intestino delgado reciben bilis del hígado/vesícula biliar y enzimas del páncreas.",
      "jejunum_ileum": "Yeyuno e íleon",
      "most_nutrient_absorption_occurs_here_v": "La mayor parte de la absorción de nutrientes ocurre aquí mediante vellosidades y microvellosidades, aumentando la superficie 600 veces. Mide 6-7 metros.",
      "large_intestine_2": "Intestino grueso",
      "water_and_electrolytes_are_reabsorbed_": "Se reabsorben agua y electrolitos. Las bacterias intestinales fermentan la fibra restante, produciendo vitaminas K y B12.",
      "rectum_excretion": "Recto y excreción",
      "waste_is_compacted_and_stored_in_the_r": "Los desechos se compactan y almacenan en el recto hasta la defecación. Todo el viaje dura 24-72 horas.",
      "path_of_a_nerve_signal": "Recorrido de una señal nerviosa",
      "trace_a_reflex_arc_from_stimulus_to_re": "Traza un arco reflejo desde el estímulo hasta la respuesta.",
      "receptor": "Receptor",
      "a_sensory_receptor_in_the_skin_detects": "Un receptor sensorial de la piel detecta un estímulo doloroso (como tocar una superficie caliente) y genera una señal eléctrica.",
      "sensory_neuron": "Neurona sensorial",
      "the_signal_travels_along_a_sensory_aff": "La señal viaja por una neurona sensorial (aferente) hacia la médula espinal a hasta 120 m/s mediante conducción saltatoria.",
      "spinal_cord_2": "Médula espinal",
      "in_the_dorsal_horn_the_sensory_neuron_": "En el asta dorsal, la neurona sensorial hace sinapsis con una interneurona. En los reflejos, la señal no necesita llegar al cerebro.",
      "interneuron": "Interneurona",
      "the_interneuron_in_the_spinal_gray_mat": "La interneurona de la sustancia gris espinal integra la señal y la transmite a una motoneurona.",
      "motor_neuron": "Motoneurona",
      "the_motor_efferent_neuron_carries_the_": "La motoneurona (eferente) lleva la señal de mando desde el asta ventral hasta el músculo diana.",
      "effector_muscle": "Efector (músculo)",
      "acetylcholine_released_at_the_neuromus": "La acetilcolina liberada en la unión neuromuscular provoca la contracción muscular. Retiras la mano antes de sentir el dolor.",
      "brain_awareness": "Consciencia cerebral",
      "meanwhile_a_copy_of_the_signal_ascends": "Mientras tanto, una copia de la señal asciende a la corteza somatosensorial. Sientes el dolor conscientemente unos 0,5 segundos después del reflejo.",
