      "find_all_primes_1_100_using_the_sieve_": "Encontrar todos los primos del 1 al 100 con la criba de Eratóstenes.",
      "fluently_decompose_any_number_from_5_t": "Descomponer con fluidez cualquier número del 5 al 10.",
      "build_mental_imagery_of_place_value_vi": "Construir una imagen mental del valor posicional mediante el ábaco.",
      "connect_the_standard_addition_algorith": "Conectar el algoritmo estándar de la suma con el reagrupamiento físico.",
      "subitize_numbers_1_6_instantly": "Subitizar los números 1-6 al instante.",
      "use_counters_as_a_thermometer_model": "Usar las fichas como modelo de termómetro.",
      "build_symmetric_designs": "Construir diseños simétricos.",
      "notice_that_adds_10_and_adds_1": "Fijarse en que ↓ añade 10 y → añade 1.",
      "find_all_trains_of_a_given_total": "Encontrar todos los «trenes» de un total dado.",
      "sort_quadrilaterals_by_their_propertie": "Clasificar cuadriláteros según sus propiedades.",
      "master_the_doubles_facts_1_1_2_2_3_3_5": "Dominar los hechos de dobles (1+1, 2+2, 3+3, ..., 5+5).",
      "estimate_before_computing": "Estimar antes de calcular.",
